// src/App.js
import React, { useEffect, useState } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import Login from "./pages/Login";
import Signup from "./pages/Signup";
import ForgotPassword from "./pages/ForgotPassword";
import DashboardLayout from "./Layout/DashboardLayout";
import DashboardHome from "./pages/DashboardHome";
import LiveTracking from "./pages/LiveTracking";
import RouteOptimization from "./pages/RouteOptimization";
import TrafficLayer from "./pages/TrafficLayer";
import Notifications from "./pages/Notifications";

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);

  // Initialize authentication state
  useEffect(() => {
    const checkAuthStatus = async () => {
      const token = localStorage.getItem("token") || sessionStorage.getItem("token");

      if (token && token !== "null" && token !== "undefined") {
        // For demo token, immediately set as authenticated
        if (token === "FAKE_TOKEN_123") {
          setIsAuthenticated(true);
          setLoading(false);
          return;
        }

        // For real JWT tokens, validate with backend
        try {
          const response = await fetch(`${process.env.REACT_APP_API_URL || 'http://localhost:8080/api'}/auth/validate`, {
            headers: {
              'Authorization': `Bearer ${token}`,
              'Content-Type': 'application/json'
            }
          });

          if (response.ok) {
            setIsAuthenticated(true);
          } else {
            // Remove invalid token
            localStorage.removeItem("token");
            sessionStorage.removeItem("token");
            localStorage.removeItem("user");
            sessionStorage.removeItem("user");
            setIsAuthenticated(false);
          }
        } catch (error) {
          console.error("Token validation failed:", error);
          // Assume token is valid for offline scenarios
          setIsAuthenticated(true);
        }
      } else {
        setIsAuthenticated(false);
      }

      setLoading(false);
    };

    checkAuthStatus();
  }, []);

  // Logout function
  const handleLogout = () => {
    localStorage.removeItem("token");
    sessionStorage.removeItem("token");
    localStorage.removeItem("user");
    sessionStorage.removeItem("user");
    setIsAuthenticated(false);
  };

  // Protected Route Component
  const ProtectedRoute = ({ children }) => {
    if (loading) {
      return (
        <div className="flex items-center justify-center min-h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
        </div>
      );
    }
    return isAuthenticated ? children : <Navigate to="/login" replace />;
  };

  // Auth Redirect Component
  const AuthRedirect = ({ children }) => {
    if (loading) {
      return (
        <div className="flex items-center justify-center min-h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div>
        </div>
      );
    }
    return isAuthenticated ? <Navigate to="/" replace /> : children;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-100">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-500 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading NeuroFleetX...</p>
        </div>
      </div>
    );
  }

  return (
    <Routes>
      {/* Authentication Routes */}
      <Route
        path="/login"
        element={
          <AuthRedirect>
            <Login setIsAuthenticated={setIsAuthenticated} />
          </AuthRedirect>
        }
      />
      <Route
        path="/signup"
        element={
          <AuthRedirect>
            <Signup />
          </AuthRedirect>
        }
      />
      <Route
        path="/forgot-password"
        element={
          <AuthRedirect>
            <ForgotPassword />
          </AuthRedirect>
        }
      />

      {/* Protected Dashboard Routes */}
      <Route
        path="/"
        element={
          <ProtectedRoute>
            <DashboardLayout onLogout={handleLogout} />
          </ProtectedRoute>
        }
      >
        <Route index element={<DashboardHome />} />
        <Route path="live-tracking" element={<LiveTracking />} />
        <Route path="route-optimization" element={<RouteOptimization />} />
        <Route path="traffic-layer" element={<TrafficLayer />} />
        <Route path="notifications" element={<Notifications />} />
      </Route>

      {/* Fallback Route */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

export default App;
